            declineButton: false, //Set to true to show decline/disable button
            declineText: '', //Text on decline/disable button
            // declineFunction: function(cookieValue){if(cookieValue=='enabled' || cookieValue=='accepted')  }, //Function to run after decline
            policyButton: false, //Set to true to show Privacy Policy button
            policyText: 'Cookie Policy', //Text on Privacy Policy button
            policyURL: '/cookie-policy/', //URL of Privacy Policy
            autoEnable: true, //Set to true for cookies to be accepted automatically. Banner still shows
